  1	import { useState, useEffect, useRef, useCallback } from 'react';
  2	
  3	export interface Staff {
  4	  name: string;
  5	  employee_id: string;
  6	  new_employee_id: string;
  7	  department: string;
  8	  organization: string;
  9	}
 10	
 11	interface StaffSearchInputProps {
 12	  onSelect: (staff: Staff) => void;
 13	  placeholder?: string;
 14	  className?: string;
 15	}
 16	
 17	// 全局缓存字典数据
 18	let staffCache: Staff[] | null = null;
 19	let cachePromise: Promise<Staff[]> | null = null;
 20	
 21	async function loadStaffDictionary(): Promise<Staff[]> {
 22	  if (staffCache) return staffCache;
 23	  if (cachePromise) return cachePromise;
 24	  
 25	  cachePromise = fetch('/staff_dictionary.json')
 26	    .then(res => res.json())
 27	    .then(data => {
 28	      staffCache = data;
 29	      return data;
 30	    });
 31	  
 32	  return cachePromise;
 33	}
