 35	export function StaffSearchInput({ onSelect, placeholder = "搜索姓名或工号...", className = "" }: StaffSearchInputProps) {
 36	  const [query, setQuery] = useState('');
 37	  const [results, setResults] = useState<Staff[]>([]);
 38	  const [isOpen, setIsOpen] = useState(false);
 39	  const [isLoading, setIsLoading] = useState(false);
 40	  const inputRef = useRef<HTMLInputElement>(null);
 41	  const containerRef = useRef<HTMLDivElement>(null);
 42	
 43	  // 搜索逻辑
 44	  const search = useCallback(async (searchQuery: string) => {
 45	    if (!searchQuery.trim()) {
 46	      setResults([]);
 47	      return;
 48	    }
 49	
 50	    setIsLoading(true);
 51	    const staffList = await loadStaffDictionary();
 52	    const lowerQuery = searchQuery.toLowerCase();
 53	    
 54	    const filtered = staffList.filter(staff => 
 55	      staff.name.toLowerCase().includes(lowerQuery) ||
 56	      staff.employee_id.toLowerCase().includes(lowerQuery) ||
 57	      staff.new_employee_id.toLowerCase().includes(lowerQuery)
 58	    ).slice(0, 10); // 最多显示10条
 59	    
 60	    setResults(filtered);
 61	    setIsLoading(false);
 62	  }, []);
 63	
 64	  // 防抖搜索
 65	  useEffect(() => {
 66	    const timer = setTimeout(() => {
 67	      search(query);
 68	    }, 200);
 69	    return () => clearTimeout(timer);
 70	  }, [query, search]);
 71	
 72	  // 点击外部关闭
 73	  useEffect(() => {
 74	    function handleClickOutside(event: MouseEvent) {
 75	      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
 76	        setIsOpen(false);
 77	      }
 78	    }
 79	    document.addEventListener('mousedown', handleClickOutside);
 80	    return () => document.removeEventListener('mousedown', handleClickOutside);
 81	  }, []);
 82	
 83	  const handleSelect = (staff: Staff) => {
 84	    onSelect(staff);
 85	    setQuery(staff.name);
 86	    setIsOpen(false);
 87	  };
 88	
 89	  return (
 90	    <div ref={containerRef} className={`relative ${className}`}>
 91	      <input
 92	        ref={inputRef}
 93	        type="text"
 94	        value={query}
 95	        onChange={(e) => {
 96	          setQuery(e.target.value);
 97	          setIsOpen(true);
 98	        }}
 99	        onFocus={() => setIsOpen(true)}
100	        placeholder={placeholder}
101	        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-pink-500 focus:border-transparent"
102	      />
103	      
104	      {isLoading && (
105	        <div className="absolute right-3 top-1/2 -translate-y-1/2">
106	          <div className="w-4 h-4 border-2 border-pink-500 border-t-transparent rounded-full animate-spin"></div>
107	        </div>
108	      )}
109	      
110	      {isOpen && results.length > 0 && (
111	        <div className="absolute z-50 w-full mt-1 bg-white border border-gray-200 rounded-lg shadow-lg max-h-60 overflow-auto">
112	          {results.map((staff, index) => (
113	            <button
114	              key={index}
115	              type="button"
116	              onClick={() => handleSelect(staff)}
117	              className="w-full px-4 py-2 text-left hover:bg-pink-50 transition-colors border-b border-gray-100 last:border-0"
118	            >
119	              <div className="flex items-center justify-between">
120	                <span className="font-medium text-gray-900">{staff.name}</span>
121	                <span className="text-sm text-gray-500">
122	                  {staff.employee_id || staff.new_employee_id || '-'}
123	                </span>
124	              </div>
125	              <div className="text-xs text-gray-400 mt-0.5">
126	                {staff.department} · {staff.organization}
127	              </div>
128	            </button>
129	          ))}
130	        </div>
131	      )}
132	      
133	      {isOpen && query && results.length === 0 && !isLoading && (
134	        <div className="absolute z-50 w-full mt-1 bg-white border border-gray-200 rounded-lg shadow-lg">
135	          <div className="px-4 py-3 text-gray-500 text-sm">未找到匹配的人员</div>
136	        </div>
137	      )}
138	    </div>
139	  );
140	}
